def kth_ordered(words, k):
    if not words or k <= 0:
        return None

    # Group words by their length and sort each group reverse-alphabetically
    word_dict = {}
    for word in words:
        length = len(word)
        if length not in word_dict:
            word_dict[length] = []
        word_dict[length].append(word)

    for key in word_dict:
        word_dict[key].sort(reverse=True)

    # Flatten the dictionary into a sorted list by length
    ordered_words = [word for sublist in word_dict.values() for word in sublist]

    if k > len(ordered_words):
        return None

    return ordered_words[k-1]
